static inline void drawMonochromeMSB(U8G2& display, uint8_t x, uint8_t y,
                                                                         uint16_t w, uint16_t h, const uint8_t* bitmap) {
    const uint16_t bytesPerRow = (w + 7U) / 8U;
    for (uint16_t row = 0; row < h; ++row) {
        for (uint16_t col = 0; col < w; ++col) {
            const uint16_t index = row * bytesPerRow + (col / 8U);
            const uint8_t byteVal = pgm_read_byte(&bitmap[index]);
            const uint8_t bitMask = (uint8_t)(0x80U >> (col & 0x07U));
            if (byteVal & bitMask) {
                display.drawPixel(x + col, y + row);
            }
        }
    }
}

static inline void drawEspNowLinkIcon10x10(U8G2& display, uint8_t x, uint8_t y, bool linked) {
    const uint8_t cx = x + 5;
    const uint8_t cy = y + 8;
    const uint8_t upper = U8G2_DRAW_UPPER_LEFT | U8G2_DRAW_UPPER_RIGHT;

    display.drawCircle(cx, cy, 1, upper);
    display.drawCircle(cx, cy, 2, upper);
    display.drawCircle(cx, cy, 4, upper);

    if (linked) {
        display.drawDisc(cx, cy, 1, U8G2_DRAW_ALL);
    } else {
        display.drawPixel(cx, cy);
        display.drawLine(x + 1, y + 9, x + 8, y + 2);
    }
}

static inline void drawFireIcon14x14(U8G2& display, uint8_t x, uint8_t y, uint8_t fireFrame) {
    uint8_t wobble = (fireFrame & 0x01) ? 1 : 0;
    display.drawDisc(x + 6, y + 10, 3, U8G2_DRAW_ALL);
    display.drawDisc(x + 7, y + 7, 3, U8G2_DRAW_ALL);
    display.drawDisc(x + 6 + wobble, y + 4, 2, U8G2_DRAW_ALL);
    display.drawDisc(x + 7, y + 8, 1, U8G2_DRAW_ALL);
}

static inline void drawFanIcon14x14(U8G2& display, uint8_t x, uint8_t y, uint8_t frame) {
    static const int8_t dir[8][2] = {
        { 0, -6}, { 4, -4}, { 6,  0}, { 4,  4},
        { 0,  6}, {-4,  4}, {-6,  0}, {-4, -4}
    };

    const uint8_t idx = frame & 0x07;
    const uint8_t idx90 = (idx + 2) & 0x07;
    const uint8_t idx180 = (idx + 4) & 0x07;
    const uint8_t idx270 = (idx + 6) & 0x07;

    const int16_t cx = x + 7;
    const int16_t cy = y + 7;

    display.drawCircle(cx, cy, 6, U8G2_DRAW_ALL);
    display.drawDisc(cx, cy, 1, U8G2_DRAW_ALL);

    display.drawLine(cx, cy, cx + dir[idx][0], cy + dir[idx][1]);
    display.drawLine(cx, cy, cx + dir[idx90][0], cy + dir[idx90][1]);
    display.drawLine(cx, cy, cx + dir[idx180][0], cy + dir[idx180][1]);
    display.drawLine(cx, cy, cx + dir[idx270][0], cy + dir[idx270][1]);
}

